#include<stdio.h>
#include<stdlib.h>
int a[1001],n2=0;
void insert(int x){int i=0;while(i<n2&&a[i]!=x)i++;if(i==n2)a[n2++]=x;}
void del(int x){int i=0;while(i<n2&&a[i]!=x)i++;if(i<n2){for(int j=i;j<n2-1;j++)a[j]=a[j+1];n2--;}}
int cmp(const void*a,const void*b){return*(int*)a-*(int*)b;}
int main(){int n,k;scanf("%d %d",&n,&k);for(int i=0;i<n;i++){int x;scanf("%d",&x);insert(x);}for(int i=0;i<k;i++){int x;scanf("%d",&x);del(x);}qsort(a,n2,sizeof(int),cmp);for(int i=0;i<n2;i++)printf("%d%c",a[i],i<n2-1?' ':'\n');}
